[data-moduix-theme='contrast'] {
  color-scheme: light;
  --background: oklch(0.995 0.001 250);
  --foreground: oklch(0.145 0.018 250);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.145 0.018 250);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.145 0.018 250);
  --primary: oklch(0.46 0.2 255);
  --primary-foreground: oklch(1 0 0);
  --secondary: oklch(0.94 0.012 250);
  --secondary-foreground: oklch(0.18 0.025 250);
  --muted: oklch(0.93 0.01 250);
  --muted-foreground: oklch(0.39 0.026 250);
  --accent: oklch(0.9 0.04 245);
  --accent-foreground: oklch(0.16 0.04 250);
  --border: oklch(0.72 0.025 250);
  --input: oklch(0.62 0.035 250);
  --ring: oklch(0.5 0.19 255);
  --overlay: oklch(0.09 0.018 250 / 0.38);
  --overlay-foreground: oklch(0.09 0.018 250 / 0.12);
  --sidebar: oklch(0.965 0.005 250);
  --sidebar-foreground: oklch(0.145 0.018 250);
  --sidebar-primary: oklch(0.46 0.2 255);
  --sidebar-primary-foreground: oklch(1 0 0);
  --sidebar-accent: oklch(0.9 0.04 245);
  --sidebar-accent-foreground: oklch(0.16 0.04 250);
  --sidebar-border: oklch(0.72 0.025 250);
  --sidebar-ring: oklch(0.5 0.19 255);
  --radius: 0.375rem;
  --shadow-sm: 0 1px 2px rgb(15 23 42 / 0.1);
  --shadow-md: 0 4px 10px rgb(15 23 42 / 0.14);
  --shadow-lg: 0 16px 30px rgb(15 23 42 / 0.18);

  .dark,
  &.dark {
    color-scheme: dark;
    --background: oklch(0.11 0.018 250);
    --foreground: oklch(0.985 0.004 250);
    --card: oklch(0.155 0.022 250);
    --card-foreground: oklch(0.985 0.004 250);
    --popover: oklch(0.155 0.022 250);
    --popover-foreground: oklch(0.985 0.004 250);
    --primary: oklch(0.76 0.13 255);
    --primary-foreground: oklch(0.12 0.02 250);
    --secondary: oklch(0.24 0.026 250);
    --secondary-foreground: oklch(0.985 0.004 250);
    --muted: oklch(0.225 0.024 250);
    --muted-foreground: oklch(0.76 0.018 250);
    --accent: oklch(0.3 0.06 250);
    --accent-foreground: oklch(0.985 0.004 250);
    --border: oklch(0.8 0.025 250 / 0.34);
    --input: oklch(0.82 0.025 250 / 0.42);
    --ring: oklch(0.74 0.13 255);
    --overlay: oklch(0.04 0.014 250 / 0.84);
    --overlay-foreground: oklch(0.985 0.004 250 / 0.12);
    --sidebar: oklch(0.13 0.02 250);
    --sidebar-foreground: oklch(0.985 0.004 250);
    --sidebar-primary: oklch(0.76 0.13 255);
    --sidebar-primary-foreground: oklch(0.12 0.02 250);
    --sidebar-accent: oklch(0.3 0.06 250);
    --sidebar-accent-foreground: oklch(0.985 0.004 250);
    --sidebar-border: oklch(0.8 0.025 250 / 0.34);
    --sidebar-ring: oklch(0.74 0.13 255);
  }
}
